import{_ as t,o,c as r,ae as a}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Create Journeys Banners or Interstitials","description":"","frontmatter":{"title":"Create Journeys Banners or Interstitials","slug":"create-journey-banner-or-interstitial"},"headers":[],"relativePath":"marketer-hub/create-journey-banner-or-interstitial.md","filePath":"marketer-hub/create-journey-banner-or-interstitial.md"}'),i={name:"marketer-hub/create-journey-banner-or-interstitial.md"};function n(s,e,l,d,u,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To create a Journey, you first need to:</p><ul><li>Integrate the <a href="./native-sdks-overview.html">Branch SDK</a> into your app and configure deep link routing and attribution.</li><li>Add your <code>xxxx-alternate.app.link</code> domain in your Associated Domains. Journeys uses your alternate domain for iOS Universal Links and Android App Links. If you use a custom domain or subdomain for your Branch Links, add entries for both <code>applinks:[mycustomdomainorsubdomain]</code> and <code>XXXX-alternate.app.link</code>.</li><li>Add the <a href="./web-sdk-overview.html">Branch Web SDK</a> to your site.</li></ul><h2 id="_1-select-audience" tabindex="-1">1. Select audience <a class="header-anchor" href="#_1-select-audience" aria-label="Permalink to &quot;1. Select audience&quot;">​</a></h2><p>To create a Journey, click <strong>Create</strong> on the top right of any page on the Branch Dashboard, then select <strong>Journey</strong>. You can also select <strong>Create a New Journey</strong> on the <strong>Journeys</strong> page.</p><p>Customize the audience that will see your Journey by completing the following fields:</p><ol><li><p><strong>Name Your Journey</strong>: Enter a name for your Journey. This name appears in the Branch Dashboard and is not visible to your users. Use a naming convention for easy reference later, such as: Date - Template - OS - Target.</p></li><li><p><strong>What campaign is it part of?</strong>: The campaign name defaults to the Journey name.</p></li><li><p><strong>What channel is it part of?</strong>: This optional field helps you analyze your Journey performance later.</p></li><li><p><strong>Select the audience you want to target</strong>: Customize the audience that will see your Journey. All conditions must be true for the Journey to display.</p><ul><li><strong>Platform</strong>: Select <strong>Mobile Web</strong>, <strong>AMP Web</strong>, or <strong>Desktop</strong>. You can select <strong>Mobile Web</strong> and <strong>AMP Web</strong> together. Selecting <strong>Desktop</strong> prevents you from selecting the other options.</li><li><strong>Devices</strong>: If you selected <strong>Mobile Web</strong>, <strong>AMP Web</strong>, or both, select which mobile operating systems and device types to target.</li><li><strong>Browser Targeting</strong>: Use the dropdown menu to select which browsers to target. You can add multiple browsers. The available browser options depend on your <strong>Platform</strong> selections.</li></ul></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Only Branch Standard Banner Bottom is supported on AMP because Google requires banners to appear in the top 75% of an AMP page.</p></div><ol start="5"><li><p><strong>This Journey will show if user</strong>: Add user-targeting filters using the following options.</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td>Has completed event</td><td>Target users based on events you define if you have <a href="./track-branch-events.html">event tracking</a> set up. For example, show a Journey to users who completed a purchase.</td></tr><tr><td>Is located</td><td>Target or exclude users viewing your website in different regions by country, state/province, or city. The location list is powered by MaxMind.</td></tr><tr><td>Is viewing a page url</td><td>Define which subsets of your website display the Journey. For example, if you have <code>yoursite.com/settings</code> and <code>yoursite.com/products/1234</code>, enter &quot;products&quot; so only users visiting a URL containing that substring see the Journey.</td></tr><tr><td>Came directly from a url</td><td>Target users based on their last touchpoint before entering your website. For example, to target users from Google Search, select &quot;whose domain matches&quot; and enter &quot;google.com&quot;.</td></tr><tr><td>Has visited web</td><td>Target users based on the number of days they have visited your website (for example, users who visited at least 5 days). You can define criteria using &quot;greater than,&quot; &quot;equal to,&quot; &quot;less than,&quot; or &quot;in between&quot; logic. A drop-down menu lets you switch between &quot;Days&quot; and &quot;Time&quot; modes. &quot;Time&quot; mode cannot be used with time-bound banners.</td></tr><tr><td>Has visited the app</td><td>Target users by app visits. For example, encourage users who visited the app twice and are now on mobile web to return to the app. Note: This audience filter relies on <code>has_app</code>, which has <a href="./what-are-the-limitations-to-has-app.html">limitations as defined here</a>.</td></tr><tr><td>Has clicked on Email</td><td>Target users who clicked a link from Branch Email. Use this for users who were part of an email campaign, such as prompting app downloads for those on mobile web without the app.</td></tr><tr><td>Has clicked on Ad</td><td>Target users who clicked a link from Deep Linked Feeds. Use this to target users from ad campaigns with a specific call to action to improve ROI.</td></tr><tr><td>Has the app installed</td><td>Target users based on app installation status. For example, only show an &quot;Open the app&quot; Journey to users who already have it installed. Note: This audience filter relies on <code>has_app</code>, which has <a href="./what-are-the-limitations-to-has-app.html">limitations as defined here</a>.</td></tr><tr><td>Is viewing a page with metadata key</td><td>Target users viewing web pages with specific metadata. Specify this data in HTML tags, in the <code>init()</code> call, or using the <code>track()</code> call. Format HTML tags as <a href="https://help.branch.io/developers-hub/docs/web-advanced-features" target="_blank" rel="noreferrer">Branch hosted deep link data</a>.</td></tr><tr><td>Has interacted with Journey</td><td>Target users who interacted with a specific Journey by choosing the Journey, interaction type, and time window. For example, display Journey A only to users who dismissed Journey B in the past seven days.</td></tr></tbody></table></li></ol><div class="info custom-block"><p class="custom-block-title">Tips on filtering</p><ul><li>Using multiple filters creates an &quot;and&quot; condition. The Journey only displays if all conditions are true.</li><li>You can add additional options for each filter, such as adding different URLs for an exact matching clause.</li><li>For URL filters, multiple URL entries create an &quot;or&quot; condition. The Journey displays if a user visits either URL A or URL B.</li><li>If your web page ends with &quot;?&quot;, the question mark is treated as an optional expression quantifier for the <strong>viewing a page URL starting with</strong> filter. For example, setting &quot;yoursite.com/?&quot; causes the Journey to appear on &quot;yoursite.com/?&quot;, &quot;yoursite.com/settings&quot;, or &quot;yoursite.com/&quot;.</li><li>For certain filters (such as <em>is viewing page url exactly matching</em>), click <strong>Edit All</strong> to paste multiple values. This creates an OR condition for that filter.</li></ul><p>You can also view example audience suggestions <a href="./example-journeys.html">here</a>.</p></div><ol start="6"><li>Click <strong>Save and Continue</strong> when you&#39;re ready to move to the next phase.</li></ol><h2 id="_2-configure-creatives" tabindex="-1">2. Configure creatives <a class="header-anchor" href="#_2-configure-creatives" aria-label="Permalink to &quot;2. Configure creatives&quot;">​</a></h2><p>In this phase, design the creative your audience will see, or add multiple view variations to A/B test the experience.</p><ol><li><p><strong>Add Variation</strong>: Run an A/B test by designing multiple templates and assigning a percentage of your audience to each one (totaling 100%). Click <strong>Add Variation +</strong> to add a new Journey banner or interstitial, and use the percentage fields to control the ratio of your audience that sees each variation.</p></li><li><p>Click <strong>Select Creative</strong> to start designing your banner or interstitial. On the Templates page, click <strong>Use</strong> on the template you want to work with.</p></li></ol><h3 id="wysiwyg" tabindex="-1">WYSIWYG <a class="header-anchor" href="#wysiwyg" aria-label="Permalink to &quot;WYSIWYG&quot;">​</a></h3><p>First, name your creative in the <strong>View Name</strong> field. Use a naming convention for easy reference. Branch uses a What You See Is What You Get (WYSIWYG) editor to simplify customization. In the preview window, click the element you want to customize, such as Icon, Title, Description, Star Rating, or <a href="https://help.branch.io/using-branch/docs/journeys-image-recommendations" target="_blank" rel="noreferrer">Background Image</a>.</p><h3 id="advanced-ui-editor" tabindex="-1">Advanced UI editor <a class="header-anchor" href="#advanced-ui-editor" aria-label="Permalink to &quot;Advanced UI editor&quot;">​</a></h3><p>For more detailed tweaks, use the <strong>CSS Editor</strong>, <strong>HTML Editor</strong>, and <strong>Page Placement</strong> tabs to customize your creative to match your brand guidelines.</p><div class="info custom-block"><p class="custom-block-title">Advanced UI configuration</p><p>Branch has a detailed guide on advanced UI configuration <a href="./advanced-journeys-ui-html-css.html">here</a>.</p></div><h3 id="dismissal-settings" tabindex="-1">Dismissal settings <a class="header-anchor" href="#dismissal-settings" aria-label="Permalink to &quot;Dismissal settings&quot;">​</a></h3><p>Adjust the Journey behavior when users dismiss the creative on the <strong>Dismissal Settings</strong> tab.</p><table tabindex="0"><thead><tr><th>Customization</th><th>Description</th></tr></thead><tbody><tr><td>Dismissal Behavior</td><td>Choose what happens when a user dismisses a Journey. &quot;Close Journey&quot; closes the Journey. &quot;Redirect to a web page&quot; closes the Journey and redirects to a specified webpage.</td></tr><tr><td>Dismissal Period</td><td>Select how long the Journey remains dismissed using the dropdown. Then decide whether dismissing this Journey also dismisses only this Journey or all Journeys for the chosen period.</td></tr></tbody></table><p>Click <strong>Save &amp; Close</strong> when you finish customizing your creative.</p><p>You will return to the Configure Creatives step, where you can see the name of the creative you created. You can create another variation or click <strong>Save and Continue</strong>.</p><h2 id="_3-validate-and-test" tabindex="-1">3. Validate and test <a class="header-anchor" href="#_3-validate-and-test" aria-label="Permalink to &quot;3. Validate and test&quot;">​</a></h2><p>In the <strong>Validation</strong> section, green checkmarks indicate everything is set up properly. If you see any errors, return to that step to complete the configuration. Access a list of errors and their meanings under <a href="./troubleshoot-journey-app-banners.html">Troubleshooting</a>.</p><p>If you have multiple variations, use the dropdown menu to preview them.</p><h3 id="preview-the-journey" tabindex="-1">Preview the Journey <a class="header-anchor" href="#preview-the-journey" aria-label="Permalink to &quot;Preview the Journey&quot;">​</a></h3><p>Once everything is validated, test the Journey by:</p><ol><li>Enter a URL to your website where the Branch Web SDK is integrated and click <strong>Get Test Link</strong>.</li><li>Visit the generated unique link in your mobile web browser to preview the Journey. Note that the preview ignores your targeting settings because it forces the view to trigger on page load.</li></ol><h3 id="schedule-the-journey" tabindex="-1">Schedule the Journey <a class="header-anchor" href="#schedule-the-journey" aria-label="Permalink to &quot;Schedule the Journey&quot;">​</a></h3><p>When you&#39;re ready to run your Journey, click <strong>Schedule</strong>. In the <strong>Schedule</strong> box, configure the following:</p><ul><li>Start/Stop Time and Date</li><li>Repeat Settings (Daily/Weekly)</li><li>Time Zone</li></ul><p>Click <strong>Start Journey</strong> to run your Journey immediately. Otherwise, click <strong>Save &amp; Close</strong> to start it later.</p>',34)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
